function injectSportsIntoItinerary(days, sportPlaces) {
  const updated = days.map((day) => ({ ...day }));
  sportPlaces.forEach((place) => {
    const targetIndex = findDayIndexForRegion(updated, REGION_LABELS[place.region] || place.region);
    if (targetIndex >= 0) {
      const label = place.type === "golf" ? "高尔夫" : "网球";
      updated[targetIndex].detail += ` ${label}选配：${place.name}（${place.duration}）。`;
    }
  });
  return updated;
}

function findDayIndexForRegion(days, regionLabel) {
  const index = days.findIndex((day) => day.region === regionLabel);
  if (index >= 0) return index;
  return days.findIndex((day) => day.region !== "返程" && day.region !== "选配");
}

function createPlan(input = {}) {
  const modules = normalizeModules(input.modules);
  const inferredProgramType = modules.length ? inferProgramTypeFromModules(modules) : input.programType;
  const preferences = {
    healing: clampNumber((input.healing ?? 4) + getModuleBoost(modules, "healing"), 1, 5),
    vacation: clampNumber((input.vacation ?? 4) + getModuleBoost(modules, "vacation"), 1, 5),
    comfort: clampNumber((input.comfort ?? 4) + getModuleBoost(modules, "comfort"), 1, 5),
    sports: normalizeSportTypes(input.sports ?? []),
  };
  const durationDays = clampNumber(input.durationDays ?? 7, 5, 8);
  const programType = inferredProgramType || "healing-vacation";
  const plan = buildDayPlan(programType, durationDays, preferences);
  const hotelTier = HOTEL_TIERS[input.hotelTier] ? input.hotelTier : "fiveStar";
  const quarter = QUARTERS[input.quarter] ? input.quarter : "q2";
  const travelers = clampNumber(input.travelers ?? 2, 1, 12);
  const modulePlaces = getModulePlaces(modules);
  const selected = mergeSelectedPlaces(plan.selected, modulePlaces);
  const suggestedPrice = getQuarterlyPriceRange(programType, durationDays, hotelTier, quarter);
  const profitModel = calculateProfitModel({
    programType,
    durationDays,
    hotelTier,
    quarter,
    travelers,
    modules,
    sports: preferences.sports,
    priceRange: suggestedPrice,
  });
  const hotelMaterials = getHotelStayMaterials(plan.route, hotelTier);

  return {
    preferences,
    modules,
    hotelTier,
    quarter,
    travelers,
    durationDays,
    ...plan,
    selected,
    profitModel,
    hotelMaterials,
    commercial: {
      packageName: getPackageName(modules, plan.program.name, durationDays),
      suggestedPrice,
      positioning: plan.program.promise,
      hotelRule: `${HOTEL_TIERS[hotelTier].name} · ${HOTEL_TIERS[hotelTier].note}`,
      seasonalNote: `${QUARTERS[quarter].name} · ${QUARTERS[quarter].note}`,
      quoteCta: "提交偏好后生成报价摘要，可用于人工跟进酒店、课程和车辆报价。",
    },
  };
}

function getHotelStayMaterials(route, hotelTier) {
  const routeRegions = new Set(route.map((step) => step.region));
  return HOTEL_STAY_MATERIALS.filter((hotel) => routeRegions.has(hotel.region) && hotel.tiers.includes(hotelTier));
}

function calculateProfitModel({ programType, durationDays, hotelTier, quarter, travelers, modules, sports, priceRange }) {
  const nights = durationDays - 1;
  const price = parsePriceRange(priceRange);
  const hotelNight = getHotelNightCost(hotelTier, quarter);
  const experienceCost = getExperienceCost(programType, modules, sports);
  const vehicleCost = 900 + Math.max(0, durationDays - 5) * 180;
  const conciergeCost = 650 + durationDays * 120;
  const insuranceCost = 0;
  const contingencyRate = 0.08;

  const perPersonBase =
    hotelNight * nights +
    experienceCost +
    vehicleCost / Math.max(1, travelers) +
    conciergeCost / Math.max(1, travelers) +
    insuranceCost;
  const perPersonCost = roundPrice(perPersonBase * (1 + contingencyRate));
  const lowProfit = price.low - perPersonCost;
  const highProfit = price.high - perPersonCost;
  const lowMargin = Math.round((lowProfit / price.low) * 100);
  const highMargin = Math.round((highProfit / price.high) * 100);

  return {
    travelers,
    perPersonCost,
    groupCost: perPersonCost * travelers,
    perPersonProfit: { low: lowProfit, high: highProfit },
    groupProfit: { low: lowProfit * travelers, high: highProfit * travelers },
    margin: { low: lowMargin, high: highMargin },
    breakdown: {
      hotelPerNight: hotelNight,
      hotelTotal: hotelNight * nights,
      experiences: experienceCost,
      vehicleShare: roundPrice(vehicleCost / Math.max(1, travelers)),
      conciergeShare: roundPrice(conciergeCost / Math.max(1, travelers)),
      insurance: insuranceCost,
      insuranceNote: "保险不计入套餐成本，建议客户自行购买覆盖巴厘岛当地医疗、意外、延误和高风险活动的旅行保险。",
      contingencyRate,
    },
    warning: lowMargin < 25 ? "毛利偏低，需要提高售价或降低酒店/体验成本。" : "毛利区间可接受，仍需用真实房价复核。",
  };
}

function getHotelNightCost(hotelTier, quarter) {
  const base = {
    fiveStar: 1350,
    cliffLuxury: 2600,
  }[hotelTier] || 1350;
  return roundPrice(base * QUARTERS[quarter].multiplier);
}

function getExperienceCost(programType, modules, sports) {
  let cost = 1500;
  if (programType === "subconscious-healing") cost += 900;
  if (programType === "deep-healing") cost += 700;
  if (modules.includes("body")) cost += 650;
  if (modules.includes("spiritual")) cost += 650;
  if (modules.includes("vacation")) cost += 300;
  if (modules.includes("sightseeing")) cost += 280;
  if (sports.includes("tennis")) cost += 450;
  if (sports.includes("golf")) cost += 1200;
  return cost;
}

function normalizeModules(modules = []) {
  if (!Array.isArray(modules)) return [];
  return modules.filter((module) => MODULES[module]);
}

function getPackageName(modules, fallbackName, durationDays) {
  if (!modules.length) return `${durationDays}天${fallbackName}`;
  const names = modules.map((module) => MODULES[module].name);
  if (names.length === 1) return `${durationDays}天${names[0]}定制旅修`;
  if (names.length === 2) return `${durationDays}天${names[0]} + ${names[1]}旅修`;
  return `${durationDays}天${names.slice(0, -1).join(" + ")} + ${names.at(-1)}定制`;
}

function inferProgramTypeFromModules(modules) {
  if (modules.includes("movement") && !modules.includes("spiritual")) return "sport-reset";
  if (modules.includes("spiritual") && !modules.includes("vacation")) return "subconscious-healing";
  if (modules.includes("spiritual") && modules.includes("body")) return "subconscious-healing";
  if (modules.includes("vacation")) return "healing-vacation";
  return "healing-vacation";
}

function getModuleBoost(modules, key) {
  return modules.reduce((sum, module) => sum + (MODULES[module].preferenceBoost[key] || 0), 0);
}

function getModulePlaces(modules) {
  const ids = [...new Set(modules.flatMap((module) => MODULES[module].placeIds))];
  return ids
    .map((id) => PLACES.find((place) => place.id === id))
    .filter(Boolean)
    .map((place) => ({ ...place, status: "模块推荐", rank: 0 }));
}

function mergeSelectedPlaces(selected, additions) {
  const byId = new Map();
  [...selected, ...additions].forEach((place) => {
    if (!byId.has(place.id)) byId.set(place.id, place);
  });
  return [...byId.values()];
}

function getQuarterlyPriceRange(programType, durationDays, hotelTier, quarter) {
  const base = parsePriceRange(getPriceRange(programType, durationDays));
  const multiplier = HOTEL_TIERS[hotelTier].multiplier * QUARTERS[quarter].multiplier;
  const low = roundPrice(base.low * multiplier);
  const high = roundPrice(base.high * multiplier);
  return `${low}-${high} 元/人`;
}

function parsePriceRange(range) {
  const matches = range.match(/(\d+)-(\d+)/);
  if (!matches) return { low: 9990, high: 13900 };
  return { low: Number(matches[1]), high: Number(matches[2]) };
}

function roundPrice(value) {
  return Math.round(value / 100) * 100;
}

function getPriceRange(programType, durationDays) {
  if (programType === "deep-healing") return durationDays >= 7 ? "11900-16900 元/人" : "8990-12900 元/人";
  if (programType === "subconscious-healing") return durationDays >= 7 ? "13900-18900 元/人" : "10900-14900 元/人";
  if (programType === "sport-reset") return durationDays >= 7 ? "10900-15900 元/人" : "8990-12900 元/人";
  return durationDays >= 7 ? "12900-17900 元/人" : "9990-13900 元/人";
}


